/**
 * Minified placeholder - Moodle will use amd/src/dragdrop.js when not in production.
 * @module mod_kolbtest/dragdrop
 */
define(["jquery"],function($){"use strict";var dragged=null;function init(){var form=document.getElementById("kolbtest-form");if(!form)return;var lists=document.querySelectorAll(".mod_kolbtest-sortable");lists.forEach(function(list){list.querySelectorAll(".mod_kolbtest-option").forEach(function(item){item.setAttribute("draggable",!0);item.addEventListener("dragstart",onDragStart);item.addEventListener("dragend",onDragEnd);item.addEventListener("dragover",onDragOver);item.addEventListener("drop",onDrop)})});form.addEventListener("submit",onSubmit)}function onDragStart(e){dragged=e.currentTarget;e.dataTransfer.effectAllowed="move";e.dataTransfer.setData("text/html",e.currentTarget.innerHTML);e.currentTarget.classList.add("mod_kolbtest-dragging")}function onDragEnd(e){e.currentTarget.classList.remove("mod_kolbtest-dragging");dragged=null}function onDragOver(e){e.preventDefault();e.dataTransfer.dropEffect="move";var target=e.currentTarget;if(target.classList.contains("mod_kolbtest-option")&&target!==dragged){var list=target.closest(".mod_kolbtest-sortable");var all=Array.from(list.querySelectorAll(".mod_kolbtest-option"));var idx=all.indexOf(target);var draggedIdx=all.indexOf(dragged);if(idx!==draggedIdx){if(idx>draggedIdx)target.parentNode.insertBefore(dragged,target.nextSibling);else target.parentNode.insertBefore(dragged,target)}}}function onDrop(e){e.preventDefault()}function onSubmit(e){var order={};document.querySelectorAll(".mod_kolbtest-sortable").forEach(function(list){var q=list.getAttribute("data-question");var indices=[];list.querySelectorAll(".mod_kolbtest-option").forEach(function(li){indices.push(parseInt(li.getAttribute("data-index"),10))});order[q]=indices});var input=document.getElementById("kolbtest-order");if(input)input.value=JSON.stringify(order)}return{init:init}});
